export interface HarmonyAssumedCredentials {
    accessKeyId: string;
    secretAccessKey: string;
    sessionToken: string;
    /**
     * Credentials expiration datetime in ISO-8601 format.
     */
    expiration: string;
}
export interface CloudAuthToken {
    challenge: {
        issuer: string;
        realm: string;
        scope: string[];
    };
    host: string;
    scope: string[];
    token: string;
    tokenType: string;
    ttlMillis: number;
}
export interface ApiRegistrationParams {
    url: string;
    roleArn: string;
    region: string;
    service?: string;
    externalId?: string;
}
export interface ApiRegistrationOptions {
    registerPathPrefix?: boolean;
}
export interface AssumeOptions {
    /** the duration in seconds of the session. Cannot exceed 3600 */
    duration?: number;
    /** the {@link https://docs.aws.amazon.com/IAM/latest/UserGuide/id_roles_create_for-user_externalid.html external id} */
    externalId?: string;
}
export interface HarmonyAuthorization {
    /**
     * Assumes a role through the Harmony API account.
     *
     * @param {String} roleArn the role to assume.
     * @param {Object} options additional options. All properties are optional
     * @return {Promise<HarmonyAssumedCredentials>} A promise that resolves to a {@code HarmonyAssumedCredentials} object.
     */
    assume: (roleArn: string, options?: AssumeOptions) => Promise<HarmonyAssumedCredentials>;
    /**
     * Fetches a token from CloudAuth for a given challenge and host. This method will first attempt to assume the
     * specified roleArn, and use the resulting temporary credentials to authenticate to the CloudAuth authentication servers.
     *
     * @param {String} challenge The challenge is the value of the "www-authenticate" header returned from an unauthorized
     *          request to the resource server. For more details on the flow of making CloudAuth requests, see documentation
     *          [here](https://w.amazon.com/index.php/Dev.CDO/UnifiedAuth/CloudAuth/FAQ#HHowdoesCloudAuthwork3F)
     * @param {String} host the resource server hostname - e.g "myhost.amazon.com".
     * @param {String} roleArn the role ARN to assume.
     * @return {Promise<CloudAuthToken>} A promise that resolves to a {@code CloudAuthToken} object.
     */
    getCloudAuthToken: (challenge: string, host: string, roleArn: string) => Promise<CloudAuthToken>;
    /**
     * Configures an endpoint to require that requests to it be signed with SigV4. Requests will be signed using
     * the temporary credentials acquired by assuming the specified IAM role. Note that when calling an API Gateway endpoint,
     * this role must have the proper permissions to invoke it. Once an endpoint has been configured using this method,
     * all subsequent requests made to it (via window.fetch and XMLHttpRequest) will automatically be signed with the credentials.
     *
     * @param {ApiRegistrationParams} params the registration parameters.
     * @param {ApiRegistrationOptions} options any additional options
     */
    registerApi: (params: ApiRegistrationParams, options?: ApiRegistrationOptions) => void;
}
